+fn deterministic_bytes(len: usize, seed: u64) -> Vec<u8> {
+    let mut state = seed.wrapping_add(1);
+    let mut out = vec![0u8; len];
+    for byte in &mut out {
+        state ^= state >> 12;
+        state ^= state << 25;
+        state ^= state >> 27;
+        let value = state.wrapping_mul(0x2545_F491_4F6C_DD1D);
+        *byte = (value & 0xFF) as u8;
+    }
+    out
+}
